// ============================================================
// src/context/AuthContext.js
// Global authentication state using React Context API
// Provides: currentUser, login(), logout(), isAuthenticated
// ============================================================
import React, { createContext, useState, useContext, useEffect } from 'react';
import { getUser, saveUser, removeUser } from '../services/data';

// Create the context
const AuthContext = createContext(null);

// ── AuthProvider wraps the entire app ────────────────────────
export const AuthProvider = ({ children }) => {
  // Initialize user from localStorage so login persists on refresh
  const [currentUser, setCurrentUser] = useState(() => getUser());

  // Keep localStorage in sync whenever currentUser changes
  useEffect(() => {
    if (currentUser) saveUser(currentUser);
    else removeUser();
  }, [currentUser]);

  /** Log in: stores user in state + localStorage */
  const login = (user) => {
    setCurrentUser(user);
  };

  /** Log out: clears state + localStorage */
  const logout = () => {
    setCurrentUser(null);
  };

  const value = {
    currentUser,
    login,
    logout,
    isAuthenticated: !!currentUser,
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

// Custom hook for convenience
export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
  return ctx;
};

export default AuthContext;
